doCmd({ cmd: "GetContracts", data: { filter: `name = 'Cuota Parte - Incedio'` } });

const isTodayInRange = (effectiveDate, endDate) => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const start = new Date(effectiveDate);
  start.setHours(0, 0, 0, 0);

  let end = null;
  if (endDate) {
    end = new Date(endDate);
    end.setHours(0, 0, 0, 0);
  }

  return (
    start <= today &&
    (end === null || end >= today)
  );
};

const resultado = GetContracts.outData;

const contrato = resultado.find(x => isTodayInRange(x.effectiveDate, x.endDate));

doCmd({ cmd: "GetPing", data: { data: contrato } });

return contrato.id ?? 0;
